import { useEffect, useRef, useState } from "react";
import { getCookie, useDeviceLocation } from "../Helper/commonfunc";
import "./styles/payment.css";
import PropTypes from "prop-types";

export default function AmountMobileForm({ rentData, mobileNo, typeSet, amountInt }) {
  console.log("AmountMobileForm Props:", { rentData, mobileNo, typeSet, amountInt });
  
  // Fixed amount - NOT EDITABLE
  const finalAmount = amountInt || 0;
  const [amount, setAmount] = useState(finalAmount);
  const [mobile, setMobile] = useState(mobileNo || "");
  const { location } = useDeviceLocation();
  const [isFrame, setIsFrame] = useState(false);
  const [keyGroup, setKeyGroup] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const formRef = useRef(null);

  // Validate amount
  const isValidAmount = amount >= 10 && amount <= 50000;

  // Handle Submit - Vegaah Gateway
  const handleSubmit = async (e) => {
    if (e) e.preventDefault();
    
    if (!isValidAmount) {
      setError("Amount must be between ₹10 and ₹50,000");
      return;
    }
    
    if (!mobile || mobile.length !== 10) {
      setError("Please enter valid 10-digit mobile number");
      return;
    }

    setIsLoading(true);
    setError("");

    try {
      // Vegaah Gateway API Call
      const apiUrl = typeSet === "service" 
        ? `https://chagans.com/pg1/checkoutConc`
        : `https://chagans.com/payment/addMoneyTen`;

      const res = await fetch(apiUrl, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          authorization: "",
          latitude: location.latitude,
          longitude: location.longitude,
        },
        body: JSON.stringify({
          amount: amount,
          mobile: mobile,
          rentData: rentData,
          pgType: "fastag",  // Changed to vegaah
          apiType: "API",
        }),
      });

      const data = await res.json();
      console.log("Vegaah Response:", data);

      if (data.success) {
        if (typeSet !== "service") {
          // For payment gateway - redirect to Vegaah
          setIsFrame(true);
          setKeyGroup(data.data);
          setTimeout(() => {
            if (formRef.current) {
              formRef.current.submit();
            }
          }, 500);
        } else if (typeSet === "service" && data.data?.transactionId) {
          // For service payments
          window.open(
            data.data.paymentLink?.linkUrl + data.data.transactionId,
            "_blank"
          );
        } else {
          setError(data.message || "Something went wrong");
        }
      } else {
        setError(data.message || "Payment initialization failed");
      }
    } catch (error) {
      console.error("Payment Error:", error);
      setError("Network error. Please check your connection.");
    } finally {
      setIsLoading(false);
    }
  };

  // Auto-submit when amount and mobile are provided
  useEffect(() => {
    if (amountInt && mobileNo && amountInt >= 10 && amountInt <= 50000) {
      // Small delay to ensure component is mounted
      setTimeout(() => {
        handleSubmit();
      }, 100);
    }
  }, [amountInt, mobileNo]);

  return (
    <div className="amount-mobile-form">
      <h2 className="form-title">
        {typeSet === "service" ? "Complete Payment" : "Pay with Vegaah"}
      </h2>

      {!isFrame ? (
        <form onSubmit={handleSubmit} className="payment-form">
          {/* Amount Field - READ ONLY / NOT EDITABLE */}
          <div className="form-group">
            <label className="form-label">Amount (₹)</label>
            <input
              type="number"
              value={amount}
              readOnly
              disabled
              className="form-input form-input-readonly"
              style={{ backgroundColor: "#f0f0f0", cursor: "not-allowed" }}
            />
            <div className="input-hint">Amount is fixed and cannot be changed</div>
          </div>

          {/* Mobile Number Field - Can be edited if needed */}
          <div className="form-group">
            <label className="form-label">Customer Mobile Number</label>
            <input
              type="tel"
              value={mobile}
              onChange={(e) => setMobile(e.target.value)}
              placeholder="Enter 10-digit mobile number"
              pattern="[0-9]{10}"
              maxLength={10}
              required
              className="form-input"
              disabled={isLoading}
            />
            <div className="input-hint">We'll send payment confirmation to this number</div>
          </div>

          {/* Error Message */}
          {error && (
            <div className="error-message">
              <span className="error-icon">⚠️</span>
              <span>{error}</span>
            </div>
          )}

          {/* Submit Button */}
          <button 
            type="submit" 
            className="submit-button" 
            disabled={isLoading || !isValidAmount || mobile.length !== 10}
          >
            {isLoading ? (
              <>
                <span className="button-loader"></span>
                <span>Processing...</span>
              </>
            ) : (
              <>
                <span>💳</span>
                <span>Pay ₹{amount.toLocaleString('en-IN')}</span>
              </>
            )}
          </button>

          <p className="payment-note">
            🔒 Secure payment via Vegaah Gateway
          </p>
        </form>
      ) : (
        <div className="payment-form">
          <form
            action={keyGroup?.APIURL}
            method="POST"
            ref={formRef}
            className="hidden-form"
          >
            {keyGroup &&
              Object.entries(keyGroup)
                .filter(([key]) => key !== "APIURL")
                .filter(([key]) => key !== "mobile")
                .map(([key, value]) => (
                  <input
                    type="hidden"
                    key={key}
                    name={key.toUpperCase()}
                    value={value}
                  />
                ))}
          </form>
          <div className="redirecting-container">
            <div className="spinner"></div>
            <p>Redirecting to Vegaah Payment Gateway...</p>
            <p className="redirect-note">Please wait, you'll be redirected shortly</p>
          </div>
        </div>
      )}
    </div>
  );
}

AmountMobileForm.propTypes = {
  rentData: PropTypes.object,
  mobileNo: PropTypes.string,
  typeSet: PropTypes.string,
  amountInt: PropTypes.number,
};
